181	// Codemirror plugin to select an autosuggest option using the mouse
182	export const selectAutocompleteOnHoverPlugin = ViewPlugin.fromClass(
183	  class SelectAutocompleteOnHoverPlugin {
184	    optionsLength = 0;
185	    lastIndex = -1;
186	
187	    constructor(readonly view: EditorView) {
188	      this.view.dom.addEventListener('mousemove', (this.onMouseMove = this.onMouseMove.bind(this)));
189	    }
190	
191	    update(update: ViewUpdate) {
192	      this.optionsLength = currentCompletions(update.state).length;
193	    }
194	
195	    findHoveredOptionIndex(dom: HTMLElement) {
196	      let listItem: HTMLElement | null = null;
197	
198	      while (dom && dom !== this.view.dom) {
199	        if (dom.nodeName === 'LI') {
200	          listItem = dom;
201	          break;
202	        }
203	        dom = dom.parentElement;
204	      }
205	
206	      if (!listItem || !listItem.parentNode) {
207	        return -1;
208	      }
209	
210	      return Array.from(listItem.parentNode.children).indexOf(listItem);
211	    }
212	
213	    onMouseMove(e: Event) {
214	      const element = e.target;
215	      const index = this.findHoveredOptionIndex(element as HTMLElement);
216	
217	      if (index >= 0 && this.lastIndex !== index) {
218	        this.lastIndex = index;
219	        this.view.dispatch({ effects: setSelectedCompletion(index) });
220	      }
221	    }
222	
223	    destroy() {
224	      this.view.dom.removeEventListener('mousemove', this.onMouseMove);
225	    }
226	  },
227	);
