229	export const promqlHighlighter = HighlightStyle.define([
230	  { tag: tags.name, color: '#000' },
231	  { tag: tags.number, color: 'var(--pf-t--global--color--status--success--default)' },
232	  { tag: tags.string, color: 'var(--pf-t--global--color--status--danger--200)' },
233	  { tag: tags.keyword, color: 'var(--pf-t--global--color--status--custom--200)', fontWeight: 'bold' },
234	  {
235	    tag: tags.function(tags.variableName),
236	    color: 'var(--pf-t--global--color--status--custom--200)',
237	    fontWeight: 'bold',
238	  },
239	  { tag: tags.labelName, color: 'var(--pf-t--global--color--status--warning--200)' },
240	  { tag: tags.operator },
241	  { tag: tags.modifier, color: 'var(--pf-t--global--color--status--custom--200)', fontWeight: 'bold' },
242	  { tag: tags.paren },
243	  { tag: tags.squareBracket },
244	  { tag: tags.brace },
245	  { tag: tags.invalid, color: 'red' },
246	  { tag: tags.comment, color: '#888', fontStyle: 'italic' },
247	]);
