249	export const PromQLExpressionInput: React.FC<PromQLExpressionInputProps> = ({
250	  value,
251	  onExecuteQuery,
252	  onValueChange,
253	  onSelectionChange,
254	}) => {
255	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
256	
257	  const containerRef = React.useRef<HTMLDivElement | null>(null);
258	  const viewRef = React.useRef<EditorView | null>(null);
259	  const [metricNames, setMetricNames] = React.useState<Array<string>>([]);
260	  const [errorMessage, setErrorMessage] = React.useState<string | undefined>();
261	
262	  const placeholder = t('Expression (press Shift+Enter for newlines)');
263	
264	  // eslint-disable-next-line react-hooks/exhaustive-deps
265	  const safeFetch = React.useCallback(useSafeFetch(), []);
266	
267	  React.useEffect(() => {
268	    safeFetch(`${PROMETHEUS_BASE_PATH}/${PrometheusEndpoint.LABEL}/__name__/values`)
269	      .then((response) => {
270	        const metrics = response?.data;
271	        setMetricNames(metrics);
272	      })
273	      .catch((err) => {
274	        if (err.name !== 'AbortError') {
275	          const message =
276	            err?.response?.status === 403
277	              ? t('Access restricted.')
278	              : t('Failed to load metrics list.');
279	          setErrorMessage(message);
280	        }
281	      });
282	  }, [safeFetch, t]);
283	
284	  const onClear = () => {
285	    if (viewRef.current !== null) {
286	      const length = viewRef.current.state.doc.toString().length;
287	      viewRef.current.dispatch({ changes: { from: 0, to: length } });
288	    }
289	    onValueChange('');
290	  };
291	
292	  React.useEffect(() => {
293	    if (viewRef.current !== null) {
294	      const currentExpression = viewRef.current.state.doc.toString();
295	      if (currentExpression !== value) {
296	        viewRef.current.dispatch({
297	          changes: { from: 0, to: currentExpression.length, insert: value },
298	        });
299	      }
300	    }
301	  }, [value]);
302	
303	  const target = React.useMemo(
304	    () => ({
305	      focus: () => viewRef.current.focus(),
306	      setSelectionRange: (from: number, to: number) => {
307	        viewRef.current.dispatch({
308	          selection: { anchor: from, head: to },
309	        });
310	      },
311	    }),
312	    [],
313	  );
314	
315	  React.useEffect(() => {
316	    promqlExtension.setComplete({
317	      remote: {
318	        url: PROMETHEUS_BASE_PATH,
319	        httpMethod: 'GET',
320	        cache: { initialMetricList: metricNames },
321	      },
322	    });
323	
324	    if (viewRef.current === null) {
325	      if (!containerRef.current) {
326	        throw new Error('expected CodeMirror container element to exist');
327	      }
328	
329	      const startState = EditorState.create({
330	        doc: value,
331	        extensions: [
332	          theme,
333	          highlightSpecialChars(),
334	          history(),
335	          EditorState.allowMultipleSelections.of(true),
336	          indentOnInput(),
337	          bracketMatching(),
338	          closeBrackets(),
339	          autocompletion(),
340	          selectAutocompleteOnHoverPlugin,
341	          highlightSelectionMatches(),
342	          EditorView.lineWrapping,
343	          EditorView.contentAttributes.of({ 'aria-label': placeholder }),
344	          keymap.of([
345	            ...closeBracketsKeymap,
346	            ...defaultKeymap,
347	            ...historyKeymap,
348	            ...completionKeymap,
349	            ...lintKeymap,
350	          ]),
351	          codeMirrorPlaceholder(placeholder),
352	          syntaxHighlighting(promqlHighlighter),
353	          promqlExtension.asExtension(),
354	          keymap.of([
355	            {
356	              key: 'Escape',
357	              run: (v: EditorView): boolean => {
358	                v.contentDOM.blur();
359	                return false;
360	              },
361	            },
362	          ]),
363	          Prec.highest(
364	            keymap.of([
365	              {
366	                key: 'Enter',
367	                run: (): boolean => {
368	                  onExecuteQuery?.();
369	                  return true;
370	                },
371	              },
372	              {
373	                key: 'Shift-Enter',
374	                run: insertNewlineAndIndent,
375	              },
376	            ]),
377	          ),
378	          EditorView.updateListener.of((update: ViewUpdate): void => {
379	            const { from, to } = update.state.selection.main;
380	            onSelectionChange?.(target, from, to);
381	
382	            const expressionValue = update.state.doc.toString();
383	            onValueChange(expressionValue);
384	          }),
385	        ],
386	      });
387	
388	      const view = new EditorView({
389	        state: startState,
390	        parent: containerRef.current,
391	      });
392	
393	      viewRef.current = view;
394	
395	      view.focus();
396	    }
397	  }, [metricNames, onValueChange, onExecuteQuery, placeholder, value, onSelectionChange, target]);
398	
399	  const handleBlur = () => {
400	    if (viewRef.current !== null) {
401	      closeCompletion(viewRef.current);
402	    }
403	  };
404	
405	  return (
406	    <div className="query-browser__query pf-v5-c-dropdown">
407	      <div
408	        ref={containerRef}
409	        onBlur={handleBlur}
410	        className="pf-v6-c-form-control query-browser__query-input"
411	      ></div>
412	      {errorMessage && (
413	        <div
414	          className="pf-v6-c-form__helper-text"
415	          id="helper-text-promql-expression-input"
416	          aria-live="polite"
417	        >
418	          <div className="pf-v6-c-helper-text">
419	            <div className="pf-v6-c-helper-text__item pf-v5-m-warning">
420	              <YellowExclamationTriangleIcon className="pf-v6-c-helper-text__item-icon" />
421	              <span className="pf-v6-c-helper-text__item-text">{errorMessage}</span>
422	            </div>
423	          </div>
424	        </div>
425	      )}
426	      <Button
427	        aria-label={t('Clear query')}
428	        className="query-browser__clear-icon"
429	        onClick={onClear}
430	        variant="plain"
431	      >
432	        <CloseIcon />
433	      </Button>
434	    </div>
435	  );
436	};

